/**
 * @summary Get recent activity feed for dashboard
 */
export const getGetRecentActivityUrl = (params?: GetRecentActivityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/analytics/recent-activity?${stringifiedParams}`
    : `/api/analytics/recent-activity`;
};

export const getRecentActivity = async (
  params?: GetRecentActivityParams,
  options?: RequestInit,
): Promise<ActivityLog[]> => {
  return customFetch<ActivityLog[]>(getGetRecentActivityUrl(params), {
    ...options,
    method: "GET",
  });
};

